  "title": "IN ऑपरेटर का उपयोग",
  "group": "SQL ऑपरेटर",
  "options": [
    {
      "text": "अद्वितीय पंक्तियों को लौटाता है"
    },
    {
      "text": "एक अनुक्रमित कॉलम की आवश्यकता होती है"
    },
    {
      "text": "केवल संख्यात्मक कॉलम पर लागू होता है"
    },
    {
      "text": "निर्दिष्ट सूची में मानों से मेल खाने वाली पंक्तियों को लौटाता है"
    }
  ],
  "questionProse": [
    "SQL में `IN` ऑपरेटर क्या करता है?"
  ],
  "explanationProse": [
    "`IN` ऑपरेटर पंक्तियों को फ़िल्टर करता है ताकि वे निर्दिष्ट सूची में किसी भी मान से मेल खाएँ, अक्सर कई OR शर्तों के विकल्प के रूप में।\n\n    जबकि यह *हो सकता है* \"अद्वितीय पंक्तियों\" को लौटाए (और अक्सर करता है), यह मुख्य उद्देश्य नहीं है।\n\n    यहाँ अनुक्रमण आवश्यक नहीं है, हालांकि यह निश्चित रूप से एक सर्वश्रेष्ठ अभ्यास है कि `IN` को ऐसे कॉलम पर उपयोग किया जाए जिसमें अनुक्रमण हो, आदर्श रूप से `UNIQUE` अनुक्रमण, क्योंकि यह प्रदर्शन को बेहतर बना सकता है।"
  ]
}
